@doc "Count Collatz conjecture steps for n=27"
@schema main : () -> i64
@f 0 main
  [
    let n 27
    let steps 0
    while > n 1
      [
        if == % n 2 0
          [ set n / n 2 ]
          [ set n + * 3 n 1 ]
        set steps + steps 1
      ]
    steps
  ]
@assert == result 111

